CREATE OR REPLACE FUNCTION public.calculate_gps_distance(lat1 double precision, lon1 double precision, lat2 double precision, lon2 double precision)
 RETURNS double precision
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  earth_radius CONSTANT DOUBLE PRECISION := 6371000; -- Earth radius in meters
  dlat DOUBLE PRECISION;
  dlon DOUBLE PRECISION;
  a DOUBLE PRECISION;
  c DOUBLE PRECISION;
BEGIN
  -- Handle NULL values
  IF lat1 IS NULL OR lon1 IS NULL OR lat2 IS NULL OR lon2 IS NULL THEN
    RETURN NULL;
  END IF;

  -- Convert degrees to radians
  dlat := radians(lat2 - lat1);
  dlon := radians(lon2 - lon1);
  
  -- Haversine formula
  a := sin(dlat/2) * sin(dlat/2) + 
       cos(radians(lat1)) * cos(radians(lat2)) * 
       sin(dlon/2) * sin(dlon/2);
  c := 2 * atan2(sqrt(a), sqrt(1-a));
  
  -- Return distance in meters
  RETURN earth_radius * c;
END;
$function$

CREATE OR REPLACE FUNCTION public.check_book_ref_same_course()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.parent_id IS NOT NULL THEN
    IF NOT EXISTS (
      SELECT 1 FROM course_book_reference
      WHERE reference_id = NEW.parent_id AND course_id = NEW.course_id
    ) THEN
      RAISE EXCEPTION 'Parent reference must belong to the same course';
    END IF;
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.cleanup_expired_qr_sessions()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_deleted_count integer;
BEGIN
  DELETE FROM qr_sessions
  WHERE expires_at < now() - interval '7 days';
  
  GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
  RETURN v_deleted_count;
END;
$function$

CREATE OR REPLACE FUNCTION public.fn_enforce_can_host_on_status_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Rule: can_host can ONLY be TRUE if status is 'active'
  -- If status is non-active, force can_host to FALSE
  IF NEW.status != 'active' THEN
    NEW.can_host := FALSE;
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.generate_qr_session(p_session_id uuid, p_attendance_date date, p_created_by text DEFAULT NULL::text, p_check_in_mode text DEFAULT 'qr_code'::text, p_linked_photo_token text DEFAULT NULL::text, p_expires_at timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_token UUID;
  v_qr_session_id UUID;
  v_session_time_str VARCHAR;
  v_session_time TIME;
  v_grace_period INTEGER;
  v_expires_at TIMESTAMPTZ;
  v_mode TEXT;
  v_linked_photo_token TEXT;
BEGIN
  v_mode := COALESCE(NULLIF(trim(p_check_in_mode), ''), 'qr_code');
  v_linked_photo_token := NULLIF(trim(COALESCE(p_linked_photo_token, '')), '');

  IF v_mode NOT IN ('qr_code', 'photo') THEN
    RAISE EXCEPTION 'Unsupported check-in mode: %', v_mode;
  END IF;

  IF v_mode = 'photo' AND v_linked_photo_token IS NULL THEN
    RAISE EXCEPTION 'Photo mode QR sessions require a linked photo token';
  END IF;

  IF v_mode = 'qr_code' THEN
    v_linked_photo_token := NULL;
  END IF;

  -- ââ Compute expiration time ââââââââââââââââââââââââââââââââââââââââââââââ
  IF p_expires_at IS NOT NULL THEN
    v_expires_at := p_expires_at;
  ELSE
    SELECT time, grace_period_minutes
    INTO v_session_time_str, v_grace_period
    FROM public.session
    WHERE session_id = p_session_id;

    IF v_session_time_str IS NULL OR v_session_time_str = '' THEN
      v_expires_at := now() + interval '2 hours';
    ELSE
      v_session_time := split_part(v_session_time_str, '-', 1)::TIME;
      v_expires_at := (p_attendance_date + v_session_time)::TIMESTAMPTZ
                      + (COALESCE(v_grace_period, 15) + 30) * interval '1 minute';
      IF v_expires_at < now() THEN
        v_expires_at := now() + interval '2 hours';
      END IF;
    END IF;
  END IF;

  -- ââ Invalidate any existing active token for the same slot âââââââââââââââ
  -- This prevents 23505 from qr_sessions_active_unique (partial index on is_valid=true)
  -- when a teacher reopens the QR modal without the previous one being closed cleanly.
  UPDATE public.qr_sessions
  SET is_valid = false
  WHERE session_id = p_session_id
    AND attendance_date = p_attendance_date
    AND check_in_mode = v_mode
    AND is_valid = true;

  -- ââ Insert fresh token ââââââââââââââââââââââââââââââââââââââââââââââââââââ
  v_token := uuid_generate_v4();

  INSERT INTO public.qr_sessions (
    token, session_id, attendance_date, expires_at,
    created_by, check_in_mode, linked_photo_token
  )
  VALUES (
    v_token, p_session_id, p_attendance_date, v_expires_at,
    p_created_by, v_mode, v_linked_photo_token
  )
  RETURNING qr_session_id INTO v_qr_session_id;

  RETURN json_build_object(
    'qr_session_id', v_qr_session_id,
    'token', v_token,
    'expires_at', v_expires_at,
    'check_in_mode', v_mode,
    'linked_photo_token', v_linked_photo_token
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.get_late_bracket_info(p_late_minutes integer, p_session_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(bracket_name character varying, bracket_name_ar character varying, score_weight numeric, display_color character varying)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_teacher_id UUID;
  v_brackets JSONB;
  v_bracket JSONB;
BEGIN
  IF p_late_minutes IS NULL OR p_late_minutes <= 0 THEN
    RETURN QUERY SELECT
      'On Time'::VARCHAR(50),
      'ÙÙ Ø§ÙÙÙØª'::VARCHAR(50),
      1.00::DECIMAL(3,2),
      '#22c55e'::VARCHAR(20);
    RETURN;
  END IF;

  IF p_session_id IS NOT NULL THEN
    SELECT s.teacher_id INTO v_teacher_id
    FROM session s WHERE s.session_id = p_session_id;
  END IF;

  SELECT sc.late_brackets INTO v_brackets
  FROM scoring_config sc
  WHERE (v_teacher_id IS NOT NULL AND sc.teacher_id = v_teacher_id)
  ORDER BY sc.is_default DESC
  LIMIT 1;

  IF v_brackets IS NOT NULL THEN
    FOR v_bracket IN SELECT * FROM jsonb_array_elements(v_brackets)
    LOOP
      IF p_late_minutes >= (v_bracket->>'min')::INT
         AND (v_bracket->>'max' IS NULL OR p_late_minutes <= (v_bracket->>'max')::INT) THEN
        RETURN QUERY SELECT
          COALESCE((v_bracket->>'name')::VARCHAR(50), 'Late'::VARCHAR(50)),
          COALESCE((v_bracket->>'name_ar')::VARCHAR(50), 'ÙØªØ£Ø®Ø±'::VARCHAR(50)),
          COALESCE((v_bracket->>'score_weight')::DECIMAL(3,2), 0.50::DECIMAL(3,2)),
          COALESCE((v_bracket->>'color')::VARCHAR(20), '#ef4444'::VARCHAR(20));
        RETURN;
      END IF;
    END LOOP;
  END IF;

  RETURN QUERY SELECT
    'Late'::VARCHAR(50),
    'ÙØªØ£Ø®Ø±'::VARCHAR(50),
    0.50::DECIMAL(3,2),
    '#ef4444'::VARCHAR(20);
END;
$function$

CREATE OR REPLACE FUNCTION public.get_late_score_weight(p_late_minutes integer, p_session_id uuid DEFAULT NULL::uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_weight DECIMAL(3,2);
  v_teacher_id UUID;
  v_brackets JSONB;
  v_bracket JSONB;
BEGIN
  IF p_late_minutes IS NULL OR p_late_minutes <= 0 THEN
    RETURN 1.00;
  END IF;

  IF p_session_id IS NOT NULL THEN
    SELECT s.teacher_id INTO v_teacher_id
    FROM session s WHERE s.session_id = p_session_id;
  END IF;

  SELECT sc.late_brackets INTO v_brackets
  FROM scoring_config sc
  WHERE (v_teacher_id IS NOT NULL AND sc.teacher_id = v_teacher_id)
  ORDER BY sc.is_default DESC
  LIMIT 1;

  IF v_brackets IS NOT NULL THEN
    FOR v_bracket IN SELECT * FROM jsonb_array_elements(v_brackets)
    LOOP
      IF p_late_minutes >= (v_bracket->>'min')::INT
         AND (v_bracket->>'max' IS NULL OR p_late_minutes <= (v_bracket->>'max')::INT) THEN
        v_weight := COALESCE((v_bracket->>'score_weight')::DECIMAL(3,2), 0.50);
        RETURN v_weight;
      END IF;
    END LOOP;
  END IF;

  RETURN 0.50;
END;
$function$

CREATE OR REPLACE FUNCTION public.invalidate_qr_session(p_token uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  UPDATE qr_sessions SET is_valid = false WHERE token = p_token;
  RETURN FOUND;
END;
$function$

CREATE OR REPLACE FUNCTION public.rls_auto_enable()
 RETURNS event_trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'pg_catalog'
AS $function$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$function$

